#include <stdio.h>
#include <unistd.h>
#include <getopt.h>
#include <stdlib.h>
#include <assert.h>
#include <string.h>
#include <string>
#include <sys/time.h>
#include <cuda_runtime.h>

#include "common.h"

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

static int do_verify = 0;

void lud_diagonal(float *m, int matrix_dim, int offset);
void lud_perimeter(float *m, int matrix_dim, int offset);
void lud_internal(float *m, int matrix_dim, int offset);

static struct option long_options[] = {
    {"input", 1, NULL, 'i'},
    {"size", 1, NULL, 's'},
    {"verify", 0, NULL, 'v'},
    {"platform", 1, NULL, 'p'},
    {"device", 1, NULL, 'd'},
    {0, 0, 0, 0}
};

int main(int argc, char *argv[])
{
#ifdef TIMING
    struct timeval tv;
    struct timeval tv_total_start;
    struct timeval tv_init_end;
    struct timeval tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
          d2h_time = 0, close_time = 0, total_time = 0;
#endif

    printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);
    size_t matrix_dim = 32;
    int opt, option_index = 0;
    func_ret_t ret;
    const char *input_file = NULL;
    float *m = NULL, *mm = NULL;
    stopwatch sw;

    while ((opt = getopt_long(argc, argv, "::vs:i:p:d:",
                              long_options, &option_index)) != -1) {
        switch (opt) {
        case 'i':
            input_file = optarg;
            break;
        case 'v':
            do_verify = 1;
            break;
        case 's':
            matrix_dim = atoi(optarg);
            printf("Generate input matrix internally, size =%lu\n", matrix_dim);
            break;
        case 'p':
            // platform_id_inuse ignored in CUDA
            break;
        case 'd':
            // device_id_inuse ignored in this CUDA version
            break;
        case '?':
            fprintf(stderr, "invalid option\n");
            break;
        case ':':
            fprintf(stderr, "missing argument\n");
            break;
        default:
            fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n",
                    argv[0]);
            exit(EXIT_FAILURE);
        }
    }

    if ((optind < argc) || (optind == 1)) {
        fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n", argv[0]);
        exit(EXIT_FAILURE);
    }

    if (input_file) {
        printf("Reading matrix from file %s\n", input_file);
        ret = create_matrix_from_file(&m, input_file, &matrix_dim);
        if (ret != RET_SUCCESS) {
            m = NULL;
            fprintf(stderr, "error create matrix from file %s\n", input_file);
            exit(EXIT_FAILURE);
        }
    }
    else if (matrix_dim) {
        printf("Creating matrix internally size=%lu\n", matrix_dim);
        ret = create_matrix(&m, matrix_dim);
        if (ret != RET_SUCCESS) {
            m = NULL;
            fprintf(stderr, "error create matrix internally size=%lu\n", matrix_dim);
            exit(EXIT_FAILURE);
        }
    }
    else {
        printf("No input file specified!\n");
        exit(EXIT_FAILURE);
    }

    if (do_verify) {
        printf("Before LUD\n");
        matrix_duplicate(m, &mm, matrix_dim);
    }

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

    // Allocate device memory
    float *d_m = NULL;
    cudaError_t err = cudaMalloc((void **)&d_m, matrix_dim * matrix_dim * sizeof(float));
    if (err != cudaSuccess) {
        fprintf(stderr, "ERROR: cudaMalloc d_m failed: %s\n", cudaGetErrorString(err));
        exit(EXIT_FAILURE);
    }

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    timersub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    // Copy host to device
    err = cudaMemcpy(d_m, m, matrix_dim * matrix_dim * sizeof(float), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "ERROR: cudaMemcpy H2D failed: %s\n", cudaGetErrorString(err));
        cudaFree(d_m);
        exit(EXIT_FAILURE);
    }

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    timersub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    int i;
    for (i = 0; i < (int)matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        // Launch lud_diagonal kernel
        dim3 dimBlockDiag(BLOCK_SIZE, 1, 1);
        dim3 dimGridDiag(1, 1, 1);
        lud_diagonal<<<dimGridDiag, dimBlockDiag>>>(d_m, matrix_dim, i);
        err = cudaGetLastError();
        if (err != cudaSuccess) {
            fprintf(stderr, "ERROR: lud_diagonal kernel launch failed: %s\n", cudaGetErrorString(err));
            cudaFree(d_m);
            exit(EXIT_FAILURE);
        }
        cudaDeviceSynchronize();

        // Launch lud_perimeter kernel
        int perimeter_blocks = ((matrix_dim - i) / BLOCK_SIZE - 1);
        if (perimeter_blocks > 0) {
            dim3 dimBlockPeri(BLOCK_SIZE * 2, 1, 1);
            dim3 dimGridPeri(perimeter_blocks, 1, 1);
            lud_perimeter<<<dimGridPeri, dimBlockPeri>>>(d_m, matrix_dim, i);
            err = cudaGetLastError();
            if (err != cudaSuccess) {
                fprintf(stderr, "ERROR: lud_perimeter kernel launch failed: %s\n", cudaGetErrorString(err));
                cudaFree(d_m);
                exit(EXIT_FAILURE);
            }
            cudaDeviceSynchronize();
        }

        // Launch lud_internal kernel
        if (perimeter_blocks > 0) {
            dim3 dimBlockInternal(BLOCK_SIZE, BLOCK_SIZE, 1);
            dim3 dimGridInternal(perimeter_blocks, perimeter_blocks, 1);
            lud_internal<<<dimGridInternal, dimBlockInternal>>>(d_m, matrix_dim, i);
            err = cudaGetLastError();
            if (err != cudaSuccess) {
                fprintf(stderr, "ERROR: lud_internal kernel launch failed: %s\n", cudaGetErrorString(err));
                cudaFree(d_m);
                exit(EXIT_FAILURE);
            }
            cudaDeviceSynchronize();
        }
    }

    // Last diagonal block
    dim3 dimBlockDiagLast(BLOCK_SIZE, 1, 1);
    dim3 dimGridDiagLast(1, 1, 1);
    lud_diagonal<<<dimGridDiagLast, dimBlockDiagLast>>>(d_m, matrix_dim, i);
    err = cudaGetLastError();
    if (err != cudaSuccess) {
        fprintf(stderr, "ERROR: lud_diagonal last kernel launch failed: %s\n", cudaGetErrorString(err));
        cudaFree(d_m);
        exit(EXIT_FAILURE);
    }
    cudaDeviceSynchronize();

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    // Copy device to host
    err = cudaMemcpy(m, d_m, matrix_dim * matrix_dim * sizeof(float), cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) {
        fprintf(stderr, "ERROR: cudaMemcpy D2H failed: %s\n", cudaGetErrorString(err));
        cudaFree(d_m);
        exit(EXIT_FAILURE);
    }

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    timersub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    timersub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    cudaFree(d_m);

    if (do_verify) {
        printf("After LUD\n");
        printf(">>>Verify<<<<\n");
        lud_verify(mm, m, matrix_dim);
        free(mm);
    }

    free(m);

    return 0;
}
